## Core Insight

The synergistic relationship between pre-training, mid-training, and reinforcement learning phases fundamentally shapes reasoning model capabilities. Rather than treating these phases in isolation, the framework reveals how each phase influences the others' efficacy. Pre-training establishes foundational knowledge representations; mid-training (continued pretraining or instruction-tuning) refines these representations; and RL aligns behavior with specific reasoning objectives.

The key innovation is understanding the precise interaction points: which capabilities require pre-training versus RL, how mid-training can bridge gaps, and what performance bottlenecks emerge from phase interactions. This enables strategic training pipeline design that maximizes reasoning performance.

## Implementation

```python
import numpy as np
from typing import Dict, List, Any, Tuple, Optional
from dataclasses import dataclass
from enum import Enum

class TrainingPhase(Enum):
    PRETRAINING = "pretraining"
    MID_TRAINING = "mid_training"
    REINFORCEMENT_LEARNING = "reinforcement_learning"

@dataclass
class PhaseMetrics:
    phase: TrainingPhase
    loss: float
    perplexity: float
    reasoning_accuracy: float
    generalization_score: float
    knowledge_coverage: float

@dataclass
class InteractionEffect:
    phase_a: TrainingPhase
    phase_b: TrainingPhase
    interaction_strength: float
    effect_direction: str
    confidence: float

@dataclass
class TrainingCheckpoint:
    phase: TrainingPhase
    step: int
    metrics: PhaseMetrics
    model_state: Dict[str, Any]
    capability_profile: Dict[str, float]

class PhasesInterplayAnalyzer:
    def __init__(self, config: Dict[str, Any]):
        self.config = config
        self.checkpoints: List[TrainingCheckpoint] = []
        self.phase_interactions: List[InteractionEffect] = []
        self.capability_trajectories: Dict[str, List[float]] = {}

    def analyze_pretraining_foundation(
        self,
        training_data: List[str],
        checkpoint_metrics: List[PhaseMetrics]
    ) -> Dict[str, Any]:
        """Evaluate knowledge foundation established by pre-training."""
        analysis = {
            "data_coverage": self._estimate_data_coverage(training_data),
            "knowledge_distribution": self._analyze_knowledge_distribution(training_data),
            "representational_capacity": self._estimate_capacity(checkpoint_metrics),
            "language_diversity": self._measure_language_diversity(training_data)
        }

        return analysis

    def _estimate_data_coverage(self, training_data: List[str]) -> float:
        """Quantify breadth of knowledge covered in pretraining data."""
        unique_tokens = len(set(' '.join(training_data).split()))
        unique_concepts = len(set(training_data))

        coverage = min(
            1.0,
            (unique_tokens / 1_000_000) * 0.5 +
            (unique_concepts / len(training_data)) * 0.5
        )

        return coverage

    def _analyze_knowledge_distribution(self, training_data: List[str]) -> Dict[str, float]:
        """Break down knowledge across domains."""
        domains = {
            "math": 0.0,
            "science": 0.0,
            "language": 0.0,
            "reasoning": 0.0,
            "other": 0.0
        }

        domain_keywords = {
            "math": ["equation", "solve", "calculate", "number", "algebra"],
            "science": ["research", "study", "hypothesis", "experiment", "physics"],
            "language": ["grammar", "syntax", "word", "phrase", "linguistic"],
            "reasoning": ["logic", "inference", "conclude", "reason", "deduct"],
        }

        for text in training_data[:100]:
            text_lower = text.lower()
            matched = False

            for domain, keywords in domain_keywords.items():
                if any(kw in text_lower for kw in keywords):
                    domains[domain] += 1
                    matched = True
                    break

            if not matched:
                domains["other"] += 1

        total = sum(domains.values()) or 1
        for domain in domains:
            domains[domain] /= total

        return domains

    def _estimate_capacity(self, metrics: List[PhaseMetrics]) -> float:
        """Estimate model's representational capacity from metrics."""
        if not metrics:
            return 0.0

        perplexities = [m.perplexity for m in metrics]
        capacity = 1.0 - (np.mean(perplexities) / (np.std(perplexities) + 100))

        return max(0.0, min(1.0, capacity))

    def _measure_language_diversity(self, training_data: List[str]) -> float:
        """Quantify diversity of languages/modalities in pretraining."""
        if not training_data:
            return 0.0

        samples = training_data[:1000]
        unique_patterns = len(set(
            ''.join(s.split()[:5]) for s in samples
        ))

        diversity = min(1.0, unique_patterns / len(samples))
        return diversity

    def evaluate_midtraining_refinement(
        self,
        pretraining_checkpoint: TrainingCheckpoint,
        midtraining_checkpoint: TrainingCheckpoint,
        target_capabilities: List[str]
    ) -> Dict[str, Any]:
        """Assess how mid-training refines pre-trained representations."""
        improvement = {}

        for capability in target_capabilities:
            pre_score = pretraining_checkpoint.capability_profile.get(capability, 0.0)
            mid_score = midtraining_checkpoint.capability_profile.get(capability, 0.0)

            improvement[capability] = {
                "delta": mid_score - pre_score,
                "percent_improvement": (
                    ((mid_score - pre_score) / (pre_score + 1e-6)) * 100
                ) if pre_score > 0 else 0,
                "alignment_with_objective": self._assess_alignment(
                    mid_score,
                    self.config.get("target_scores", {}).get(capability, 1.0)
                )
            }

        return {
            "per_capability_improvement": improvement,
            "average_improvement": np.mean([
                v["delta"] for v in improvement.values()
            ]),
            "optimization_efficiency": self._calculate_efficiency(
                pretraining_checkpoint,
                midtraining_checkpoint
            )
        }

    def _assess_alignment(self, achieved: float, target: float) -> float:
        """Measure how well achieved score aligns with target."""
        alignment = 1.0 - abs(achieved - target)
        return max(0.0, min(1.0, alignment))

    def _calculate_efficiency(
        self,
        start_checkpoint: TrainingCheckpoint,
        end_checkpoint: TrainingCheckpoint
    ) -> float:
        """Compute training efficiency (improvement per step)."""
        steps_taken = end_checkpoint.step - start_checkpoint.step
        if steps_taken == 0:
            return 0.0

        perf_improvement = (
            end_checkpoint.metrics.reasoning_accuracy -
            start_checkpoint.metrics.reasoning_accuracy
        )

        efficiency = perf_improvement / steps_taken
        return efficiency

    def analyze_rl_contribution(
        self,
        midtraining_checkpoint: TrainingCheckpoint,
        rl_checkpoint: TrainingCheckpoint,
        reward_model: callable
    ) -> Dict[str, Any]:
        """Quantify how RL aligns and improves reasoning capabilities."""
        rl_contribution = {
            "task_performance_gain": (
                rl_checkpoint.metrics.reasoning_accuracy -
                midtraining_checkpoint.metrics.reasoning_accuracy
            ),
            "alignment_score": self._compute_alignment_score(
                rl_checkpoint.capability_profile,
                reward_model
            ),
            "exploration_breadth": self._measure_exploration(
                rl_checkpoint.model_state
            ),
            "stability_metrics": self._assess_stability(
                [midtraining_checkpoint, rl_checkpoint]
            )
        }

        return rl_contribution

    def _compute_alignment_score(
        self,
        capability_profile: Dict[str, float],
        reward_model: callable
    ) -> float:
        """Calculate alignment with RL objective via reward model."""
        total_reward = 0.0
        count = 0

        for capability, score in capability_profile.items():
            try:
                reward = reward_model(capability, score)
                total_reward += reward
                count += 1
            except:
                pass

        return total_reward / (count + 1e-6)

    def _measure_exploration(self, model_state: Dict[str, Any]) -> float:
        """Quantify exploration extent in RL training."""
        if "exploration_metrics" not in model_state:
            return 0.5

        metrics = model_state["exploration_metrics"]
        trajectory_diversity = metrics.get("trajectory_diversity", 0.0)
        action_variance = metrics.get("action_variance", 0.0)

        exploration = (trajectory_diversity + action_variance) / 2
        return min(1.0, exploration)

    def _assess_stability(
        self,
        checkpoints: List[TrainingCheckpoint]
    ) -> Dict[str, float]:
        """Evaluate training stability across phases."""
        if len(checkpoints) < 2:
            return {"variance": 0.0, "trend": "stable"}

        losses = [cp.metrics.loss for cp in checkpoints]
        loss_variance = np.var(losses) if losses else 0.0

        loss_trend = "increasing" if losses[-1] > losses[0] else "decreasing"

        return {
            "loss_variance": float(loss_variance),
            "trend": loss_trend,
            "stability_score": 1.0 / (1.0 + loss_variance)
        }

    def detect_phase_interactions(
        self,
        checkpoint_timeline: List[TrainingCheckpoint]
    ) -> List[InteractionEffect]:
        """Identify interactions between training phases."""
        interactions = []

        for i in range(len(checkpoint_timeline) - 1):
            cp1 = checkpoint_timeline[i]
            cp2 = checkpoint_timeline[i + 1]

            if cp1.phase != cp2.phase:
                interaction = self._compute_interaction(cp1, cp2)
                interactions.append(interaction)
                self.phase_interactions.append(interaction)

        return interactions

    def _compute_interaction(
        self,
        checkpoint_a: TrainingCheckpoint,
        checkpoint_b: TrainingCheckpoint
    ) -> InteractionEffect:
        """Compute specific interaction between two phases."""
        acc_change = (
            checkpoint_b.metrics.reasoning_accuracy -
            checkpoint_a.metrics.reasoning_accuracy
        )

        loss_change = checkpoint_b.metrics.loss - checkpoint_a.metrics.loss

        interaction_strength = abs(acc_change) + abs(loss_change)

        effect_direction = (
            "positive" if acc_change > 0 else
            "negative" if acc_change < 0 else
            "neutral"
        )

        interaction = InteractionEffect(
            phase_a=checkpoint_a.phase,
            phase_b=checkpoint_b.phase,
            interaction_strength=interaction_strength,
            effect_direction=effect_direction,
            confidence=0.8
        )

        return interaction

    def recommend_phase_ordering(
        self,
        available_compute: float,
        target_capabilities: List[str]
    ) -> Dict[str, Any]:
        """Suggest optimal phase sequence and resource allocation."""
        total_budget = available_compute

        recommendations = {
            "phase_sequence": [
                TrainingPhase.PRETRAINING,
                TrainingPhase.MID_TRAINING,
                TrainingPhase.REINFORCEMENT_LEARNING
            ],
            "resource_allocation": self._allocate_resources(
                total_budget,
                target_capabilities
            ),
            "checkpoint_strategy": self._recommend_checkpoints(target_capabilities),
            "expected_performance": self._project_performance(target_capabilities)
        }

        return recommendations

    def _allocate_resources(
        self,
        total_budget: float,
        target_capabilities: List[str]
    ) -> Dict[TrainingPhase, float]:
        """Distribute compute budget across phases."""
        base_allocation = {
            TrainingPhase.PRETRAINING: 0.60,
            TrainingPhase.MID_TRAINING: 0.25,
            TrainingPhase.REINFORCEMENT_LEARNING: 0.15
        }

        reasoning_importance = (
            "reasoning" in str(target_capabilities).lower()
        )

        if reasoning_importance:
            base_allocation[TrainingPhase.REINFORCEMENT_LEARNING] = 0.25
            base_allocation[TrainingPhase.PRETRAINING] = 0.55

        return {
            phase: total_budget * fraction
            for phase, fraction in base_allocation.items()
        }

    def _recommend_checkpoints(self, capabilities: List[str]) -> List[Dict]:
        """Suggest checkpoint intervals and validation gates."""
        checkpoints = [
            {"phase": "pretraining", "interval_steps": 5000},
            {"phase": "mid_training", "interval_steps": 1000},
            {"phase": "rl", "interval_steps": 500}
        ]

        return checkpoints

    def _project_performance(self, target_capabilities: List[str]) -> Dict[str, float]:
        """Estimate final performance across capabilities."""
        projections = {}

        for capability in target_capabilities:
            base_perf = 0.7
            improvement_potential = 0.25

            projections[capability] = base_perf + improvement_potential

        return projections
```

## Practical Guidance

1. **Invest Majority in Pre-Training**: Allocate 55-60% of compute to establish foundational knowledge, as this constrains all downstream phases.

2. **Calibrate Mid-Training Targets**: Use mid-training (25%) to refine specific capability gaps identified from pre-training evaluation.

3. **Apply RL Selectively**: Reserve RL (15-25%) for alignment and reasoning refinement rather than knowledge acquisition.

4. **Monitor Phase Interactions**: Track checkpoint metrics across phase transitions to identify where one phase undermines another's gains.

5. **Validate Capability Preservation**: Ensure mid-training improvements don't degrade pre-training knowledge by testing on diverse benchmarks.

6. **Design Progressive Evaluation**: Test reasoning capabilities at each phase boundary to detect interaction bottlenecks early.

7. **Adjust Allocation Dynamically**: If reasoning accuracy plateaus during one phase, consider reallocating remaining compute to the next phase earlier.

## Reference

